/**
 * Parses and validates incoming message content
 */
function parseMessage(content) {
  let message;
  try {
    message = JSON.parse(content.toString());
  } catch (error) {
    throw new Error(`Invalid JSON message: ${error.message}`);
  }

  if (!message.type) {
    throw new Error('Message must have a "type" field');
  }

  if (!message.payload || typeof message.payload !== 'object') {
    throw new Error('Message must have a "payload" object');
  }

  return {
    type: message.type,
    payload: message.payload,
    correlationId: message.correlationId || null,
    timestamp: message.timestamp || new Date().toISOString(),
  };
}

/**
 * Processes a single message
 */
async function processMessage(message) {
  const handler = messageHandlers[message.type];
  if (!handler) {
    throw new Error(`Unknown message type: "${message.type}". Available types: ${Object.keys(messageHandlers).join(', ')}`);
  }

  console.log(`[PROCESS] Handling message type: ${message.type}, correlationId: ${message.correlationId}`);
  const startTime = Date.now();

  const result = await handler(message.payload);

  const duration = Date.now() - startTime;
  console.log(`[PROCESS] Completed ${message.type} in ${duration}ms`);

  return result;
}

/**
 * Gets retry count from message headers
 */
function getRetryCount(msg) {
  const deaths = msg.properties.headers && msg.properties.headers['x-death'];
  if (deaths && Array.isArray(deaths)) {
    return deaths.reduce((count, death) => count + (death.count || 0), 0);
  }
  return 0;
}

/**
 * Main entry point - sets up RabbitMQ connection and starts consuming
 */
async function start() {
  let connection;
  let channel;

  try {
    console.log('[STARTUP] Connecting to RabbitMQ...');
    connection = await amqp.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    // Set prefetch to limit concurrent message processing
    await channel.prefetch(parseInt(process.env.PREFETCH_COUNT) || 10);

    // Assert dead letter exchange and queue
    await channel.assertExchange('dlx.exchange', 'direct', { durable: true });
    await channel.assertQueue(DEAD_LETTER_QUEUE, {
      durable: true,
      arguments: {},
    });
    await channel.bindQueue(DEAD_LETTER_QUEUE, 'dlx.exchange', QUEUE_NAME);

    // Assert main queue with dead letter configuration
    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-dead-letter-exchange': 'dlx.exchange',
        'x-dead-letter-routing-key': QUEUE_NAME,
      },
    });

    console.log(`[STARTUP] Waiting for messages on queue: ${QUEUE_NAME}`);

    // Start consuming messages
    await channel.consume(QUEUE_NAME, async (msg) => {
      if (!msg) return;

      const messageId = msg.properties.messageId || 'unknown';
      const retryCount = getRetryCount(msg);

      try {
        const parsedMessage = parseMessage(msg.content);
        console.log(`[RECEIVED] messageId=${messageId}, type=${parsedMessage.type}, retry=${retryCount}`);

        const result = await processMessage(parsedMessage);
        console.log(`[SUCCESS] messageId=${messageId}, result:`, JSON.stringify(result).substring(0, 200));

        // Acknowledge successful processing
        channel.ack(msg);
      } catch (error) {
        console.error(`[ERROR] messageId=${messageId}, retry=${retryCount}, error:`, error.message);

        if (retryCount < MAX_RETRIES) {
          // Reject and requeue for retry (will go to DLQ due to dead letter config, 
          // but we nack with requeue=true for simple retry)
          console.log(`[RETRY] messageId=${messageId}, attempt ${retryCount + 1}/${MAX_RETRIES}`);
          channel.nack(msg, false, true);
        } else {
          // Max retries exceeded, send to dead letter queue
          console.error(`[DLQ] messageId=${messageId}, max retries exceeded, sending to dead letter queue`);
          channel.nack(msg, false, false);
        }
      }
    }, {
      noAck: false, // Manual acknowledgment
    });

    // Handle connection close events
    connection.on('close', (err) => {
      console.error('[CONNECTION] RabbitMQ connection closed', err?.message);
      setTimeout(() => {
        console.log('[RECONNECT] Attempting to reconnect...');
        start();
      }, 5000);
    });

    connection.on('error', (err) => {
      console.error('[CONNECTION] RabbitMQ connection error:', err.message);
    });

    channel.on('error', (err) => {
      console.error('[CHANNEL] RabbitMQ channel error:', err.message);
    });

    console.log('[STARTUP] Microservice is running and consuming messages');

  } catch (error) {
    console.error('[STARTUP ERROR]', error.message);
    // Retry connection after delay
    setTimeout(() => {
      console.log('[RECONNECT] Retrying connection...');
      start();
    }, 5000);
  }

  // Graceful shutdown
  const shutdown = async (signal) => {
    console.log(`[SHUTDOWN] Received ${signal}, shutting down gracefully...`);
    try {
      if (channel) {
        await channel.close();
        console.log('[SHUTDOWN] Channel closed');
      }
      if (connection) {
        await connection.close();
        console.log('[SHUTDOWN] Connection closed');
      }
      await pool.end();
      console.log('[SHUTDOWN] Database pool closed');
    } catch (err) {
      console.error('[SHUTDOWN ERROR]', err.message);
    }
    process.exit(0);
  };

  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));
}

// Start the microservice
start().catch((err) => {
  console.error('[FATAL]', err.message);
  process.exit(1);
});

